// 1. Static File Serving (Mimic /server/data/upload/...)
// Frontend requests: /server/data/upload/pic/xxx.png
app.use('/server/data/upload', express.static(UPLOAD_DIR, {
    maxAge: '7d',
    immutable: true
}));

app.use('/server/data/branding', express.static(BRANDING_DIR, {
    maxAge: '7d',
    immutable: true
}));
app.use('/server/data/manager-background', express.static(MANAGER_BACKGROUND_DIR, {
    maxAge: '7d',
    immutable: true
}));


app.listen(PORT, () => {
    console.log(`Server running at http://localhost:${PORT}`);
});